1	//! Graph GENERATION (BEHAVIOR.md §4, §6): mapping a proof-state / constraint-system
2	//! description onto the DOT [`Graph`] model, over an independent input model
3	//! designed from observed paired `main/proof` sequents and `interactive-graph-def`
4	//! graphs.
5	//!
6	//! What the observed system→graph mapping does, structurally (each point traces to
7	//! corpus/live observation — see BEHAVIOR.md §4, §6):
8	//!   * a **rule instance** `#t : Rule[actions]` becomes a `record` node with up to
9	//!     three groups `{premises}|{info}|{conclusions}`; the **info** group (the
10	//!     `#t : Rule[…]` cell) is always present (100 % of 160 409 corpus records),
11	//!     and an **empty** premise or conclusion group is dropped (so a source rule
12	//!     with no premises renders `{info}|{concl}`);
13	//!   * an intruder-knowledge fact renders as a gray `!KU( m ) @ #t` **ellipse**;
14	//!     a protocol action/event as a darkblue `Fact @ #t` ellipse; a compressed
15	//!     intruder rule as an uncolored `#t : rule` ellipse; a bare **timepoint**
16	//!     (`#i`, `#decrypt`, the designated `#last`) as an uncolored `#var` ellipse;
17	//!   * an unresolved node referenced by an open premise renders as an
18	//!     **invtrapezium** `(#var, idx)` (BEHAVIOR.md §3d);
19	//!   * a **role**-annotated record (role ≠ `Undefined`) is packed into a
20	//!     `subgraph "cluster_<Role>_Session_<k>"` block; role-annotated theories emit
21	//!     the compact header and free (non-role) nodes stay at the top level, in id
22	//!     order, *before* every cluster (BEHAVIOR.md §4);
23	//!   * **edges** connect a conclusion port to a premise port (structural), or an
24	//!     intruder deduction (red dashed), message (gray30), temporal order (blue3 /
25	//!     black dashed), etc. — the finite observed style vocabulary (§3c);
26	//!   * `n<K>` ids come from [`crate::alloc`]; record-cell text is wrapped/escaped
27	//!     by [`crate::doclayout::wrap_cell_dot`]; the header is inferred by role (§4).
28	//!
29	//! Two cell-content input paths, both flowing through the same wrap/escape
30	//! pipeline: [`RuleInstance`] carries [`Fact`]s (this crate renders + wraps them),
31	//! and [`RawRule`] carries PRE-RENDERED cell strings (the consumer's own printer
32	//! produced them; this crate still wraps and escapes). GAPS (need the GPL solver;
33	//! not derivable from output): *which* nodes/edges/clusters a raw constraint system
34	//! yields, the per-rule/per-cluster color hash, and the accumulated-column wrap
35	//! trigger for cells deep on a record line (BEHAVIOR.md §3f).
36	
37	use crate::alloc::NodeIdAllocator;
38	use crate::doclayout::{wrap_cell_dot, FILL_WIDTH};
39	use crate::model::*;
40	use crate::render::{render_info, Fact};
41	
42	/// The per-cell minimum wrap budget (BEHAVIOR.md §3f): inside a record group a
43	/// cell's shared budget never drops below this floor — a cell whose flat
44	/// rendering is at most this many columns never wraps, however wide its siblings
45	/// are (live probe: a sibling forced far past the budget still leaves the target
46	/// fitting at flat ≤ 20, wrapping at 21).
47	const MIN_CELL_BUDGET: usize = 20;
48	
49	/// A per-record cluster assignment (BEHAVIOR.md §4). `label` is the cluster label
50	/// WITHOUT the `cluster_` prefix (e.g. `Initiator_Session_1`, observed always
51	/// `<Role>_Session_<k>`); `color` is the 8-hex ARGB used for the block's
52	/// `color`/`fillcolor`. Both are solver-supplied (a content GAP).
53	#[derive(Clone, Debug)]
54	pub struct ClusterRef {
55	    pub label: String,
56	    pub color: String,
57	}
58	
59	impl ClusterRef {
60	    pub fn new(label: &str, color: &str) -> Self {
61	        ClusterRef { label: label.into(), color: color.into() }
62	    }
63	}
64	
65	/// A rule instance: one record node with premise / info / conclusion cells, built
66	/// from [`Fact`]s (the crate renders and wraps them).
67	#[derive(Clone, Debug)]
68	pub struct RuleInstance {
69	    pub temporal: String,
70	    pub rule: String,
71	    pub role: String,
72	    pub premises: Vec<Fact>,
73	    pub actions: Vec<Fact>,
74	    pub conclusions: Vec<Fact>,
75	    /// Per-rule fill color (a solver-side hash — a GAP; supplied by the caller).
76	    pub fillcolor: String,
77	    /// `black` on the light MSR palette, `white`/`black` on the role palette.
78	    pub fontcolor: String,
79	    /// If set, this record is packed into a `cluster_<label>` subgraph (§4).
80	    pub cluster: Option<ClusterRef>,
81	}
82	
83	impl RuleInstance {
84	    pub fn new(temporal: &str, rule: &str, fillcolor: &str) -> Self {
85	        RuleInstance {
86	            temporal: temporal.into(),
87	            rule: rule.into(),
88	            role: Role::UNDEFINED.into(),
89	            premises: Vec::new(),
90	            actions: Vec::new(),
91	            conclusions: Vec::new(),
92	            fillcolor: fillcolor.into(),
93	            fontcolor: "black".into(),
94	            cluster: None,
95	        }
96	    }
97	    pub fn premises(mut self, f: Vec<Fact>) -> Self {
98	        self.premises = f;
99	        self
100	    }
101	    pub fn actions(mut self, f: Vec<Fact>) -> Self {
102	        self.actions = f;
103	        self
104	    }
105	    pub fn conclusions(mut self, f: Vec<Fact>) -> Self {
106	        self.conclusions = f;
107	        self
108	    }
109	    pub fn role(mut self, r: &str, fontcolor: &str) -> Self {
110	        self.role = r.into();
111	        self.fontcolor = fontcolor.into();
112	        self
113	    }
114	    /// Pack this record into the `cluster_<label>` subgraph (BEHAVIOR.md §4).
115	    pub fn cluster(mut self, label: &str, color: &str) -> Self {
116	        self.cluster = Some(ClusterRef::new(label, color));
117	        self
118	    }
119	    /// The flat, un-escaped cell strings (premises, info, conclusions), for the
120	    /// shared record builder.
121	    fn spec(&self) -> RecordSpec {
122	        RecordSpec {
123	            premises: self.premises.iter().map(Fact::render_flat).collect(),
124	            info: render_info(&self.temporal, &self.rule, &self.actions),
125	            conclusions: self.conclusions.iter().map(Fact::render_flat).collect(),
126	            prem_widths: Vec::new(),
127	            concl_widths: Vec::new(),
128	            fillcolor: self.fillcolor.clone(),
129	            fontcolor: self.fontcolor.clone(),
130	            role: self.role.clone(),
131	            cluster: self.cluster.clone(),
132	        }
133	    }
134	}
135	
136	/// A rule instance whose cells are supplied as **pre-rendered flat strings**
137	/// (BEHAVIOR.md interop, round 5). The consumer renders fact/term text with its own
138	/// printer — including any abbreviation — and this crate's wrap + escape pipeline
139	/// ([`crate::doclayout::wrap_cell_dot`]) applies to those strings exactly as it does
140	/// to a [`RuleInstance`]'s rendered facts. `info` is the whole info-cell text
141	/// (`#t : Rule[…]`); `premises` and `conclusions` are one flat fact string per cell.
142	#[derive(Clone, Debug, Default)]
143	pub struct RawRule {
144	    pub premises: Vec<String>,
145	    pub info: String,
146	    pub conclusions: Vec<String>,
147	    /// Optional caller-supplied width inputs, one per premise cell (empty =
148	    /// derive everything from the display text). See [`CellWidths`].
149	    pub premise_widths: Vec<Option<CellWidths>>,
150	    /// Optional caller-supplied width inputs, one per conclusion cell.
151	    pub conclusion_widths: Vec<Option<CellWidths>>,
152	    pub fillcolor: String,
153	    pub fontcolor: String,
154	    pub role: String,
155	    pub cluster: Option<ClusterRef>,
156	}
157	
158	impl RawRule {
159	    /// A raw record with the given info-cell text and per-rule fill color; role
160	    /// defaults to `Undefined`, fontcolor to `black`.
161	    pub fn new(info: &str, fillcolor: &str) -> Self {
162	        RawRule {
163	            premises: Vec::new(),
164	            info: info.into(),
165	            conclusions: Vec::new(),
166	            premise_widths: Vec::new(),
167	            conclusion_widths: Vec::new(),
168	            fillcolor: fillcolor.into(),
169	            fontcolor: "black".into(),
170	            role: Role::UNDEFINED.into(),
171	            cluster: None,
172	        }
173	    }
174	    pub fn premises(mut self, cells: Vec<String>) -> Self {
175	        self.premises = cells;
176	        self
177	    }
178	    pub fn conclusions(mut self, cells: Vec<String>) -> Self {
179	        self.conclusions = cells;
180	        self
181	    }
182	    /// Supply per-cell width inputs for the premise group (one entry per
183	    /// premise cell; `None` entries fall back to display-text estimates).
184	    pub fn premise_widths(mut self, w: Vec<Option<CellWidths>>) -> Self {
185	        self.premise_widths = w;
186	        self
187	    }
188	    /// Supply per-cell width inputs for the conclusion group.
189	    pub fn conclusion_widths(mut self, w: Vec<Option<CellWidths>>) -> Self {
190	        self.conclusion_widths = w;
191	        self
192	    }
193	    pub fn role(mut self, r: &str, fontcolor: &str) -> Self {
194	        self.role = r.into();
195	        self.fontcolor = fontcolor.into();
196	        self
197	    }
198	    pub fn cluster(mut self, label: &str, color: &str) -> Self {
199	        self.cluster = Some(ClusterRef::new(label, color));
200	        self
201	    }
202	    fn spec(&self) -> RecordSpec {
203	        RecordSpec {
204	            premises: self.premises.clone(),
205	            info: self.info.clone(),
206	            conclusions: self.conclusions.clone(),
207	            prem_widths: self.premise_widths.clone(),
208	            concl_widths: self.conclusion_widths.clone(),
209	            fillcolor: self.fillcolor.clone(),
210	            fontcolor: self.fontcolor.clone(),
211	            role: self.role.clone(),
212	            cluster: self.cluster.clone(),
213	        }
214	    }
215	}
216	
217	/// Caller-supplied per-cell width inputs, overriding the shape-feature
218	/// estimates [`group_widths`] derives from the cell's (post-abbreviation)
219	/// display text. The reference decides row sharing on its *internal*
220	/// (UN-abbreviated) term widths, which are structurally invisible to a crate
221	/// consuming display text — a caller that knows them (e.g. an adapter sitting
222	/// on the term representation) can pass them here (BEHAVIOR.md §3f, round 10).
223	/// Every field is optional; an absent field (or an absent [`CellWidths`]
224	/// altogether) falls back to the display-text estimate, byte-identically to
225	/// the no-override path.
226	#[derive(Clone, Debug, Default, PartialEq, Eq)]
227	pub struct CellWidths {
228	    /// The cell's row **occupancy** `C` (columns it counts for in its
229	    /// siblings' trigger budgets). Display-text default:
230	    /// `flat + Σ_{top-level tuple/union args}(elems + 1)`.
231	    pub occupancy: Option<i64>,
232	    /// The cell's own trigger-budget **bonus**. Display-text default: the
233	    /// largest `⌊elems/2⌋ + 2` over its top-level tuple/union args (4 for an
234	    /// arg with ≥ 9 elements), 0 without such an arg.
235	    pub bonus: Option<i64>,
236	    /// The cell's **fill numerator** (its internal width in the proportional
237	    /// fill share once it wraps). Display-text default:
238	    /// `flat + Σ_{union args}(elems + 1) + #function-nodes`.
239	    pub fill_width: Option<i64>,
240	}
241	
242	impl CellWidths {
243	    /// An override that fixes only the row occupancy.
244	    pub fn occupancy(c: i64) -> Self {
245	        CellWidths { occupancy: Some(c), ..Default::default() }
246	    }
247	}
248	
249	/// The flat (un-escaped, un-wrapped) content of a record, shared by the Term-based
250	/// [`RuleInstance`] and the pre-rendered [`RawRule`]. Cell text is wrapped and
251	/// escaped by [`build_record`]. `prem_widths` / `concl_widths`, when non-empty,
252	/// carry one optional [`CellWidths`] per premise / conclusion cell.
253	struct RecordSpec {
254	    premises: Vec<String>,
255	    info: String,
256	    conclusions: Vec<String>,
257	    prem_widths: Vec<Option<CellWidths>>,
258	    concl_widths: Vec<Option<CellWidths>>,
259	    fillcolor: String,
260	    fontcolor: String,
261	    role: String,
262	    cluster: Option<ClusterRef>,
263	}
264	
265	impl RecordSpec {
266	    fn cell_count(&self) -> usize {
267	        self.premises.len() + 1 /* info */ + self.conclusions.len()
268	    }
269	}
270	
271	/// One node of the input system, in emission order.
272	#[derive(Clone, Debug)]
273	pub enum GraphNode {
274	    /// A rule instance built from [`Fact`]s (rendered + wrapped by this crate).
275	    Rule(RuleInstance),
276	    /// A rule instance whose cells are pre-rendered strings (still wrapped/escaped).
277	    RawRule(RawRule),
278	    /// `!KU( term ) @ #t` — intruder knowledge (drawn as a gray ellipse). `term`
279	    /// is the pre-rendered message text.
280	    Knowledge { term: String, temporal: String },
281	    /// `Fact @ #t` — a protocol action/event (darkblue ellipse). `fact` is
282	    /// pre-rendered.
283	    Action { fact: String, temporal: String },
284	    /// `#t : rule` — a compressed rule shown as a single uncolored ellipse.
285	    Compressed { temporal: String, rule: String },
286	    /// `#var` — a bare timepoint ellipse (uncolored). Observed for ordinary
287	    /// timepoint variables (`#i`, `#decrypt`, `#t1`, …) and, when a constraint
288	    /// system carries a designated last timepoint (induction), the `#last` node
289	    /// (`#last` is the target of `color="black",style="dashed"` before-edges).
290	    Temporal { var: String },
291	    /// `(#var, idx)` — an unresolved node referenced by an open premise
292	    /// (invtrapezium), the target of a conclusion→absent-node structural edge.
293	    OpenTarget { node_var: String, premise_index: usize },
294	    /// A node with an explicit `shape` and label — the extension point for shapes
295	    /// beyond the observed set (e.g. the `trapezium` dual, an unresolved source
296	    /// feeding a present premise, which is spec-named but was **not observed** in
297	    /// the corpus or any probe; see BEHAVIOR.md §3d).
298	    Shaped { label: String, shape: String, color: Option<String> },
299	}
300	
301	impl GraphNode {
302	    /// The designated last timepoint `#last` (BEHAVIOR.md §3d/§6).
303	    pub fn last() -> Self {
304	        GraphNode::Temporal { var: "last".into() }
305	    }
306	    /// A record node from a [`RecordSpec`], if this node is one.
307	    fn record_spec(&self) -> Option<RecordSpec> {
308	        match self {
309	            GraphNode::Rule(r) => Some(r.spec()),
310	            GraphNode::RawRule(r) => Some(r.spec()),
311	            _ => None,
312	        }
313	    }
314	}
315	
316	/// An endpoint reference into the input system (resolved to `n<K>[:n<port>]`).
317	#[derive(Clone, Copy, Debug)]
318	pub enum EndRef {
319	    /// The whole node (no port) — ellipses, invtrapezium, legend.
320	    Whole(usize),
321	    /// Conclusion `c` of rule node `n` (→ its conclusion port).
322	    Conclusion(usize, usize),
323	    /// Premise `p` of rule node `n` (→ its premise port).
324	    Premise(usize, usize),
325	}
326	
327	/// The finite observed edge-style vocabulary (BEHAVIOR.md §3c). Each maps to a
328	/// fixed attribute list emitted verbatim.
329	#[derive(Clone, Copy, Debug)]
330	pub enum EdgeStyle {
331	    /// `style="bold",weight="10.0",color="gray50"` — structural, into a target.
332	    StructuralGray,
333	    /// `style="bold",weight="10.0"` — structural (uncolored).
334	    Structural,
335	    /// `color="gray30"` — message / standard edge.
336	    Message,
337	    /// `color="red",style="dashed"` — intruder `!KU` deduction.
338	    KnowledgeDeduction,
339	    /// `color="orangered2"` — deduction variant.
340	    Deduction,
341	    /// `color="blue3",style="dashed"` — temporal-order edge.
342	    TemporalBlue,
343	    /// `color="black",style="dashed"` — before / less-than temporal edge (e.g. into
344	    /// the `#last` node).
345	    TemporalBlack,
346	    /// `style="invis"` — ranking edge to the legend.
347	    Invis,
348	}
349	
350	impl EdgeStyle {
351	    /// The exact attribute pairs, in observed key order.
352	    pub fn attrs(self) -> Vec<(String, String)> {
353	        let raw: &[(&str, &str)] = match self {
354	            EdgeStyle::StructuralGray => {
355	                &[("style", "bold"), ("weight", "10.0"), ("color", "gray50")]
356	            }
357	            EdgeStyle::Structural => &[("style", "bold"), ("weight", "10.0")],
358	            EdgeStyle::Message => &[("color", "gray30")],
359	            EdgeStyle::KnowledgeDeduction => &[("color", "red"), ("style", "dashed")],
360	            EdgeStyle::Deduction => &[("color", "orangered2")],
361	            EdgeStyle::TemporalBlue => &[("color", "blue3"), ("style", "dashed")],
362	            EdgeStyle::TemporalBlack => &[("color", "black"), ("style", "dashed")],
363	            EdgeStyle::Invis => &[("style", "invis")],
364	        };
365	        raw.iter().map(|(k, v)| (k.to_string(), v.to_string())).collect()
366	    }
367	}
368	
369	/// An edge in the input system.
370	#[derive(Clone, Debug)]
371	pub struct SysEdge {
372	    pub src: EndRef,
373	    pub dst: EndRef,
374	    pub style: EdgeStyle,
375	}
376	
377	impl SysEdge {
378	    pub fn new(src: EndRef, dst: EndRef, style: EdgeStyle) -> Self {
379	        SysEdge { src, dst, style }
380	    }
381	}
382	
383	/// A proof-state graph description: nodes in emission order, edges, and an
384	/// optional pre-rendered legend (inner HTML of the `plain` node) plus the invis
385	/// edges wiring it in.
386	#[derive(Clone, Debug, Default)]
387	pub struct System {
388	    pub nodes: Vec<GraphNode>,
389	    pub edges: Vec<SysEdge>,
390	    /// Legend inner HTML (from [`crate::abbrev::Abbreviator::legend_html`]); if
391	    /// non-empty a `{ rank="sink"; … }` block is appended.
392	    pub legend_html: Option<String>,
393	    /// Invis edges to the legend node (emitted after the sink block).
394	    pub legend_edges: Vec<(EndRef, ())>,
395	}
396	
397	/// Resolved ids for one system node.
398	enum Resolved {
399	    // The info port is never an edge endpoint, so it is not retained here.
400	    Record { ports_prem: Vec<String>, ports_concl: Vec<String>, node: String },
401	    Node(String),
402	}
403	
404	impl Resolved {
405	    fn node_id(&self) -> &str {
406	        match self {
407	            Resolved::Record { node, .. } => node,
408	            Resolved::Node(id) => id,
409	        }
410	    }
411	}
412	
413	/// Build the DOT [`Graph`] for a [`System`]: allocate ids in emission order (so id
414	/// order == file order), emit free (non-clustered) node statements at the top
415	/// level, then the `cluster_…` subgraph blocks (role records, grouped by cluster
416	/// label in first-appearance order), then edges, then the legend sink-block + its
417	/// invis edges. Header is inferred from roles (§4).
418	pub fn generate(sys: &System) -> Graph {
419	    let mut alloc = NodeIdAllocator::new();
420	    let mut resolved: Vec<Resolved> = Vec::with_capacity(sys.nodes.len());
421	
422	    // Free top-level node statements, in emission order.
423	    let mut free: Vec<Stmt> = Vec::new();
424	    // Clusters: label -> (color, record statements), with first-appearance order.
425	    let mut cluster_order: Vec<String> = Vec::new();
426	    let mut clusters: std::collections::HashMap<String, (String, Vec<Stmt>)> =
427	        std::collections::HashMap::new();
428	
429	    // Pass 1: allocate ids and build node statements in emission order. A clustered
430	    // record's statement is routed into its cluster bucket; everything else is free.
431	    for node in &sys.nodes {
432	        if let Some(spec) = node.record_spec() {
433	            let ids = alloc.record(spec.cell_count());
434	            let mut it = ids.ports.into_iter();
435	            let ports_prem: Vec<String> = (0..spec.premises.len()).map(|_| it.next().unwrap()).collect();
436	            let port_info = it.next().unwrap();
437	            let ports_concl: Vec<String> =
438	                (0..spec.conclusions.len()).map(|_| it.next().unwrap()).collect();
439	            let rec = build_record(&spec, &ports_prem, &port_info, &ports_concl);
440	            let stmt = Stmt::Node(Node::record(ids.node.clone(), rec));
441	            match &spec.cluster {
442	                Some(c) => {
443	                    let entry = clusters.entry(c.label.clone()).or_insert_with(|| {
444	                        cluster_order.push(c.label.clone());
445	                        (c.color.clone(), Vec::new())
446	                    });
447	                    entry.1.push(stmt);
448	                }
449	                None => free.push(stmt),
450	            }
451	            resolved.push(Resolved::Record { ports_prem, ports_concl, node: ids.node });
452	            continue;
453	        }
454	        let id = alloc.node();
455	        let stmt = match node {
456	            GraphNode::Knowledge { term, temporal } => {
457	                let label = format!("!KU( {} ) @ #{}", term, temporal);
458	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "gray")))
459	            }
460	            GraphNode::Action { fact, temporal } => {
461	                let label = format!("{} @ #{}", fact, temporal);
462	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "darkblue")))
463	            }
464	            GraphNode::Compressed { temporal, rule } => {
465	                let label = format!("#{} : {}", temporal, rule);
466	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(label)))
467	            }
468	            GraphNode::Temporal { var } => {
469	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(format!("#{}", var))))
470	            }
471	            GraphNode::OpenTarget { node_var, premise_index } => {
472	                Stmt::Node(Node::shaped(id.clone(), Shaped::invtrapezium(node_var, *premise_index)))
473	            }
474	            GraphNode::Shaped { label, shape, color } => Stmt::Node(Node::shaped(
475	                id.clone(),
476	                Shaped { label: label.clone(), shape: shape.clone(), color: color.clone() },
477	            )),
478	            GraphNode::Rule(_) | GraphNode::RawRule(_) => unreachable!("records handled above"),
479	        };
480	        free.push(stmt);
481	        resolved.push(Resolved::Node(id));
482	    }
483	
484	    // Assemble: free nodes, then clusters (first-appearance order), then edges.
485	    let mut g = Graph::new(Header::Simple);
486	    for s in free {
487	        g.push(s);
488	    }
489	    for label in &cluster_order {
490	        let (color, body) = clusters.remove(label).unwrap();
491	        g.push(Stmt::Cluster(Cluster { label: label.clone(), color, body }));
492	    }
493	
494	    // Pass 2: edges.
495	    for e in &sys.edges {
496	        let src = endpoint(&resolved, e.src);
497	        let dst = endpoint(&resolved, e.dst);
498	        g.push(Stmt::Edge(Edge { src, dst, attrs: e.style.attrs() }));
499	    }
500	
501	    // Pass 3: legend sink-block, then its invis edges (observed order).
502	    if let Some(html) = &sys.legend_html {
503	        if !html.is_empty() {
504	            let legend_id = alloc.node();
505	            let block = RankBlock {
506	                rank: "sink".into(),
507	                body: vec![Stmt::Node(Node::plain(legend_id.clone(), html.clone()))],
508	            };
509	            g.push(Stmt::RankBlock(block));
510	            for (from, ()) in &sys.legend_edges {
511	                let src = endpoint(&resolved, *from);
512	                g.push(Stmt::Edge(Edge {
513	                    src,
514	                    dst: EndPoint::node(legend_id.clone()),
515	                    attrs: EdgeStyle::Invis.attrs(),
516	                }));
517	            }
518	        }
519	    }
520	
521	    g.set_inferred_header();
522	    g
523	}
524	
525	/// Assemble a record node's model from a [`RecordSpec`] and its allocated ports.
526	/// Empty premise / conclusion groups are dropped; the info group is always kept
527	/// (matches the observed group structure). Each prem/concl group's cells share the
528	/// record wrap budget by the proportional allocation [`group_widths`]; the info
529	/// cell is its own single-cell group (budget 87). Cell text is wrapped (ragged
530	/// HughesPJ `fill`) and escaped by [`crate::doclayout::wrap_cell_dot`].
531	fn build_record(spec: &RecordSpec, ports_prem: &[String], port_info: &str, ports_concl: &[String]) -> Record {
532	    let mut columns: Vec<Vec<Cell>> = Vec::new();
533	    if !spec.premises.is_empty() {
534	        columns.push(group_cells(&spec.premises, ports_prem, &spec.prem_widths));
535	    }
536	    // The info cell is its own single-cell group (full width), fed through the
537	    // faithful layout engine at [`FILL_WIDTH`].
538	    columns.push(vec![Cell::new(port_info, wrap_cell_dot(&spec.info, FILL_WIDTH as isize))]);
539	    if !spec.conclusions.is_empty() {
540	        columns.push(group_cells(&spec.conclusions, ports_concl, &spec.concl_widths));
541	    }
542	    Record {
543	        columns,
544	        fillcolor: spec.fillcolor.clone(),
545	        fontcolor: spec.fontcolor.clone(),
546	        role: Role(spec.role.clone()),
547	    }
548	}
