550	/// Shape features of one cell's flat text that enter the row-share model
551	/// (probe-derived, BEHAVIOR.md §3f rounds 9–10): `flat` = display width;
552	/// `tup_sur` / `uni_sur` = Σ over top-level tuple / `(a++b)`-union arguments
553	/// of `elems + 1` (the round-10 occupancy law, pinned at n = 2,3,4,6 tuples
554	/// and 3,5,8 unions); `bmax` = the largest per-argument self-budget bonus
555	/// `⌊elems/2⌋ + 2` (arguments with ≥ 9 elements contribute 4); `sqa` = the
556	/// cell is a fact with exactly one argument that is a single-quoted constant
557	/// (enters only the fill weight); `nfunc` = number of function-application
558	/// nodes anywhere in the text (enters only the fill numerator).
559	struct CellShape {
560	    flat: usize,
561	    tup_sur: i64,
562	    uni_sur: i64,
563	    bmax: i64,
564	    sqa: bool,
565	    nfunc: i64,
566	}
567	
568	/// Split a term list at top-level `", "`, honoring nesting and quotes.
569	fn split_level(s: &str) -> Vec<&str> {
570	    let b: Vec<(usize, char)> = s.char_indices().collect();
571	    let mut parts = Vec::new();
572	    let (mut depth, mut inq, mut start) = (0i32, false, 0usize);
573	    let mut i = 0;
574	    while i < b.len() {
575	        let (pos, c) = b[i];
576	        if inq {
577	            if c == '\'' {
578	                inq = false;
579	            }
580	        } else {
581	            match c {
582	                '\'' => inq = true,
583	                '(' | '<' | '[' => depth += 1,
584	                ')' | '>' | ']' => depth -= 1,
585	                ',' if depth == 0 && i + 1 < b.len() && b[i + 1].1 == ' ' => {
586	                    parts.push(&s[start..pos]);
587	                    start = b[i + 1].0 + 1;
588	                    i += 1;
589	                }
590	                _ => {}
591	            }
592	        }
593	        i += 1;
594	    }
595	    parts.push(&s[start..]);
596	    parts
597	}
598	
599	/// Element count of a parenthesized top-level `++`-union `(a++b++…)`, 0 for
600	/// anything else.
601	fn union_elems(t: &str) -> i64 {
602	    if !(t.starts_with('(') && t.ends_with(')')) || t.len() < 2 {
603	        return 0;
604	    }
605	    let inner = &t[1..t.len() - 1];
606	    let b: Vec<char> = inner.chars().collect();
607	    let (mut depth, mut inq, mut n) = (0i32, false, 1i64);
608	    let mut i = 0;
609	    while i < b.len() {
610	        let c = b[i];
611	        if inq {
612	            if c == '\'' {
613	                inq = false;
614	            }
615	        } else {
616	            match c {
617	                '\'' => inq = true,
618	                '(' | '<' | '[' => depth += 1,
619	                ')' | '>' | ']' => depth -= 1,
620	                '+' if depth == 0 && i + 1 < b.len() && b[i + 1] == '+' => {
621	                    n += 1;
622	                    i += 1;
623	                }
624	                _ => {}
625	            }
626	        }
627	        i += 1;
628	    }
629	    if n >= 2 { n } else { 0 }
630	}
631	
632	fn cell_shape(flat: &str) -> CellShape {
633	    let width = flat.chars().count();
634	    let (mut tup_sur, mut uni_sur, mut bmax) = (0i64, 0i64, 0i64);
635	    let mut sqa = false;
636	    if let Some(open) = flat.find("( ") {
637	        // a padded fact with at least one argument (`Name( )` has none)
638	        if flat.ends_with(" )")
639	            && open + 2 <= flat.len() - 2
640	            && !flat[..open].contains(['(', ')', '<', '>', ' ', ','])
641	        {
642	            let inner = &flat[open + 2..flat.len() - 2];
643	            let args = split_level(inner);
644	            for a in &args {
645	                let t = a.trim();
646	                let (elems, is_tuple) = if t.starts_with('<') && t.ends_with('>') {
647	                    (split_level(&t[1..t.len() - 1]).len() as i64, true)
648	                } else {
649	                    (union_elems(t), false)
650	                };
651	                if elems >= 2 {
652	                    if is_tuple {
653	                        tup_sur += elems + 1;
654	                    } else {
655	                        uni_sur += elems + 1;
656	                    }
657	                    bmax = bmax.max(if elems <= 8 { elems / 2 + 2 } else { 4 });
658	                }
659	            }
660	            if args.len() == 1 {
661	                let a = args[0].trim();
662	                sqa = a.starts_with('\'')
663	                    && a.ends_with('\'')
664	                    && a.len() >= 2
665	                    && !a[1..a.len() - 1].contains('\'');
666	            }
667	        }
668	    }
669	    // function-application nodes: identifier directly followed by `(` with no
670	    // space after (the unpadded display form), e.g. `senc(`, `pk(`
671	    let bch: Vec<char> = flat.chars().collect();
672	    let mut nfunc = 0i64;
673	    for i in 1..bch.len() {
674	        if bch[i] == '('
675	            && (bch[i - 1].is_alphanumeric() || bch[i - 1] == '_')
676	            && (i + 1 >= bch.len() || bch[i + 1] != ' ')
677	        {
678	            nfunc += 1;
679	        }
680	    }
681	    CellShape { flat: width, tup_sur, uni_sur, bmax, sqa, nfunc }
682	}
