791	/// Resolve an [`EndRef`] to a serializer [`EndPoint`] using the id/port map.
792	fn endpoint(resolved: &[Resolved], r: EndRef) -> EndPoint {
793	    match r {
794	        EndRef::Whole(n) => EndPoint::node(resolved[n].node_id().to_string()),
795	        EndRef::Conclusion(n, c) => {
796	            if let Resolved::Record { node, ports_concl, .. } = &resolved[n] {
797	                EndPoint::port(node.clone(), ports_concl[c].clone())
798	            } else {
799	                EndPoint::node(resolved[n].node_id().to_string())
800	            }
801	        }
802	        EndRef::Premise(n, p) => {
803	            if let Resolved::Record { node, ports_prem, .. } = &resolved[n] {
804	                EndPoint::port(node.clone(), ports_prem[p].clone())
805	            } else {
806	                EndPoint::node(resolved[n].node_id().to_string())
807	            }
808	        }
809	    }
810	}
