265	                            if m {
266	                                tallies[ti].wrap_match += 1;
267	                            }
268	                            if single {
269	                                tallies[ti].single_wrap_total += 1;
270	                                if m {
271	                                    tallies[ti].single_wrap_match += 1;
272	                                }
273	                            } else {
274	                                tallies[ti].multi_wrap_total += 1;
275	                                if m {
276	                                    tallies[ti].multi_wrap_match += 1;
277	                                }
278	                            }
279	                            if !m {
280	                                if !predicted.contains("\\l") {
281	                                    tallies[ti].fn_predict_oneline += 1;
282	                                    if tallies[ti].fp_examples.len() < 25 && single {
283	                                        tallies[ti].fp_examples.push((
284	                                            flat_texts[k].clone(),
285	                                            widths[k],
286	                                            body.to_string(),
287	                                            predicted.clone(),
288	                                        ));
289	                                    }
290	                                } else {
291	                                    tallies[ti].fill_error += 1;
292	                                }
293	                            }
294	                        }
295	                    }
296	                }
297	            }
