1	//! Corpus constraint extractor (round 9): for every prem/concl record group in
2	//! the corpus, compute per cell the SET of line lengths (engine L-space,
3	//! ribbonsPerLine = 1.5) at which the exact layout engine reproduces the
4	//! observed record-cell bytes. Emits one TSV line per group:
5	//!
6	//!   file  kind(P|C)  info_flat  prem_flats  concl_flats  cells
7	//!
8	//! where `cells` is `|`-joined per-cell entries `flat:STATUS` with STATUS one of
9	//!   F<lo>        cell does not wrap; it matches at every L >= lo (lo = min)
10	//!   lo-hi[,..]   cell wraps; the L runs at which the engine output == bytes
11	//!   NONE         cell wraps; no L in [8, fitL] reproduces it (cell-doc gap)
12	//!
13	//! Groups dumped: multi-cell groups with any wrapping cell OR flat total > 80
14	//! (boundary/false-positive evidence), and single-cell wrapping groups.
15	//! Usage: band_dump <corpus_dir>... > bands.tsv
16	
17	use graph_clean::doclayout::wrap_cell_dot_lr;
18	use std::collections::HashMap;
19	
20	fn split_top(s: &str, sep: char) -> Vec<String> {
21	    let ch: Vec<char> = s.chars().collect();
22	    let mut parts = Vec::new();
23	    let mut cur = String::new();
24	    let mut depth = 0i32;
25	    let mut i = 0;
26	    while i < ch.len() {
27	        let c = ch[i];
28	        if c == '\\' && i + 1 < ch.len() {
29	            cur.push(c);
30	            cur.push(ch[i + 1]);
31	            i += 2;
32	            continue;
33	        }
34	        match c {
35	            '{' => {
36	                depth += 1;
37	                cur.push(c);
38	            }
39	            '}' => {
40	                depth -= 1;
41	                cur.push(c);
42	            }
43	            _ if c == sep && depth == 0 => parts.push(std::mem::take(&mut cur)),
44	            _ => cur.push(c),
45	        }
46	        i += 1;
47	    }
48	    parts.push(cur);
49	    parts
50	}
51	fn unescape(t: &str) -> String {
52	    t.replace("\\<", "<").replace("\\>", ">").replace("\\{", "{").replace("\\}", "}").replace("\\|", "|")
53	}
54	fn parse_record(label: &str) -> Option<Vec<Vec<String>>> {
55	    if !(label.starts_with('{') && label.ends_with('}')) {
56	        return None;
57	    }
58	    let inner = &label[1..label.len() - 1];
59	    let mut groups = Vec::new();
60	    for g in split_top(inner, '|') {
61	        let g = g.trim();
62	        if !(g.starts_with('{') && g.ends_with('}')) {
63	            return None;
64	        }
65	        groups.push(split_top(&g[1..g.len() - 1], '|'));
66	    }
67	    Some(groups)
68	}
69	fn strip_port(cell: &str) -> Option<&str> {
70	    let rest = cell.strip_prefix("<n")?;
71	    let sp = rest.find("> ")?;
72	    if !rest[..sp].chars().all(|c| c.is_ascii_digit()) {
73	        return None;
74	    }
75	    Some(&rest[sp + 2..])
76	}
77	fn is_info_body(b: &str) -> bool {
78	    b.starts_with('#') && b.contains(" : ")
79	}
80	fn dewrap(b: &str) -> String {
81	    // `,\l` = a separator break (the trailing space is dropped at line end);
82	    // `\l&nbsp;` = an indented continuation or an indented closer peel (no
83	    // character lost); a remaining col-0 `\l)` = the fact-paren peel (its
84	    // padded ` )` space was the break). Order matters.
85	    let t = b.replace(",\\l", ", ");
86	    let t = t.replace("\\l&nbsp;", "&nbsp;");
87	    let t = t.replace("\\l)", " )");
88	    let t = t.replace("\\l", "").replace("&nbsp;", "");
89	    unescape(&t)
90	}
91	fn flat_width(b: &str) -> usize {
92	    dewrap(b).chars().count()
93	}
