95	/// Smallest L (line length at ribbons 1.5) whose ribbon >= flat.
96	fn fit_l(flat: usize) -> isize {
97	    let mut l = ((flat as f64) * 1.5).floor() as isize - 2;
98	    if l < 8 {
99	        l = 8;
100	    }
101	    loop {
102	        // banker's round of L/1.5, as the engine computes the ribbon
103	        let v = l as f64 / 1.5;
104	        let fl = v.floor();
105	        let r = if (v - fl - 0.5).abs() < 1e-9 {
106	            let f = fl as i64;
107	            if f % 2 == 0 {
108	                f
109	            } else {
110	                f + 1
111	            }
112	        } else {
113	            v.round() as i64
114	        };
115	        if r >= flat as i64 {
116	            return l;
117	        }
118	        l += 1;
119	    }
120	}
