122	/// STATUS string for one cell (see module docs).
123	fn cell_status(flat_text: &str, body: &str, flat: usize) -> String {
124	    let wraps = body.contains("\\l");
125	    if !wraps {
126	        // valid L set is [lo, +inf) (monotone: below the fit boundary the doc
127	        // wraps, above it renders flat; an unbreakable atom matches everywhere)
128	        let hi = fit_l(flat) + 2;
129	        let matches = |l: isize| wrap_cell_dot_lr(flat_text, l, 1.5) == body;
130	        if matches(8) {
131	            return "F8".to_string();
132	        }
133	        let (mut lo, mut hi) = (8isize, hi);
134	        // invariant: !matches(lo), matches(hi)
135	        if !matches(hi) {
136	            return "FNONE".to_string();
137	        }
138	        while hi - lo > 1 {
139	            let mid = (lo + hi) / 2;
140	            if matches(mid) {
141	                hi = mid;
142	            } else {
143	                lo = mid;
144	            }
145	        }
146	        return format!("F{}", hi);
147	    }
148	    // wrapping: sweep 8 ..= fitL (at/above fitL the render is one line != body)
149	    let top = fit_l(flat);
150	    let mut runs: Vec<(isize, isize)> = Vec::new();
151	    let mut cur: Option<(isize, isize)> = None;
152	    for l in 8..=top {
153	        if wrap_cell_dot_lr(flat_text, l, 1.5) == body {
154	            cur = Some(match cur {
155	                Some((a, _)) => (a, l),
156	                None => (l, l),
157	            });
158	        } else if let Some(r) = cur.take() {
159	            runs.push(r);
160	        }
161	    }
162	    if let Some(r) = cur {
163	        runs.push(r);
164	    }
165	    if runs.is_empty() {
166	        return "NONE".to_string();
167	    }
168	    runs.iter().map(|(a, b)| format!("{}-{}", a, b)).collect::<Vec<_>>().join(",")
169	}
