171	/// Shape features of a cell's flat text, for occupancy-model fitting:
172	/// `(dtop, drec, nq, sqa, nargs, nfunc, nabbr, ctup, bmax)` where `dtop` = Σ
173	/// over TOP-LEVEL tuple args of (2·elems − 4), `drec` = the same over ALL
174	/// tuple nodes recursively, `nq` = number of single-quoted constants anywhere,
175	/// `sqa` = 1 if the cell is a fact with exactly one argument that is a quoted
176	/// constant, `nargs` = top-level argument count (0 if the text is not a padded
177	/// fact), `ctup` = Σ over top-level tuple AND `(a++b)`-union args of
178	/// (elems + 1) (the round-10 occupancy law), `bmax` = max over those args of
179	/// (elems/2 + 2) (the round-10 self-budget bonus law).
180	fn shape_features(flat: &str) -> (i64, i64, i64, i64, i64, i64, i64, i64, i64) {
181	    fn split_args(s: &str) -> Vec<&str> {
182	        let mut parts = Vec::new();
183	        let (mut depth, mut inq, mut start) = (0i32, false, 0usize);
184	        let b: Vec<(usize, char)> = s.char_indices().collect();
185	        let mut i = 0;
186	        while i < b.len() {
187	            let (pos, c) = b[i];
188	            if inq {
189	                if c == '\'' {
190	                    inq = false;
191	                }
192	            } else {
193	                match c {
194	                    '\'' => inq = true,
195	                    '(' | '<' | '[' => depth += 1,
196	                    ')' | '>' | ']' => depth -= 1,
197	                    ',' if depth == 0 && i + 1 < b.len() && b[i + 1].1 == ' ' => {
198	                        parts.push(&s[start..pos]);
199	                        start = b[i + 1].0 + 1;
200	                        i += 1;
201	                    }
202	                    _ => {}
203	                }
204	            }
205	            i += 1;
206	        }
207	        parts.push(&s[start..]);
208	        parts
209	    }
210	    fn tuple_nodes(s: &str, top: bool, dtop: &mut i64, drec: &mut i64) {
211	        let t = s.trim();
212	        if t.starts_with('<') && t.ends_with('>') {
213	            let inner = &t[1..t.len() - 1];
214	            let elems = split_args(inner);
215	            let d = 2 * elems.len() as i64 - 4;
216	            *drec += d;
217	            if top {
218	                *dtop += d;
219	            }
220	            for e in elems {
221	                tuple_nodes(e, false, dtop, drec);
222	            }
223	        } else if let Some(open) = t.find('(') {
224	            if t.ends_with(')') {
225	                let inner = &t[open + 1..t.len() - 1];
226	                let inner = inner.strip_prefix(' ').unwrap_or(inner);
227	                let inner = inner.strip_suffix(' ').unwrap_or(inner);
228	                for a in split_args(inner) {
229	                    tuple_nodes(a, false, dtop, drec);
230	                }
231	            }
232	        }
233	    }
234	    /// Union arg `(a++b++…)`: element count if `t` is a parenthesized
235	    /// top-level `++` chain, else 0.
236	    fn union_elems(t: &str) -> i64 {
237	        let t = t.trim();
238	        if !(t.starts_with('(') && t.ends_with(')')) {
239	            return 0;
240	        }
241	        let inner = &t[1..t.len() - 1];
242	        let b: Vec<(usize, char)> = inner.char_indices().collect();
243	        let (mut depth, mut inq, mut n) = (0i32, false, 1i64);
244	        let mut i = 0;
245	        while i < b.len() {
246	            let c = b[i].1;
247	            if inq {
248	                if c == '\'' {
249	                    inq = false;
250	                }
251	            } else {
252	                match c {
253	                    '\'' => inq = true,
254	                    '(' | '<' | '[' => depth += 1,
255	                    ')' | '>' | ']' => depth -= 1,
256	                    '+' if depth == 0 && i + 1 < b.len() && b[i + 1].1 == '+' => {
257	                        n += 1;
258	                        i += 1;
259	                    }
260	                    _ => {}
261	                }
262	            }
263	            i += 1;
264	        }
265	        if n >= 2 { n } else { 0 }
266	    }
267	    let nq = flat.split('\'').count() as i64 / 2;
268	    let (mut dtop, mut drec) = (0i64, 0i64);
269	    let mut nargs = 0i64;
270	    let mut sqa = 0i64;
271	    let (mut ctup, mut bmax) = (0i64, 0i64);
272	    // function-application nodes inside the fact (name directly followed by
273	    // '(' with no ' ' after — the unpadded display form), e.g. senc(, pk(
274	    let nfunc = {
275	        let b: Vec<char> = flat.chars().collect();
276	        let mut n = 0i64;
277	        for i in 1..b.len() {
278	            if b[i] == '('
279	                && (b[i - 1].is_alphanumeric() || b[i - 1] == '_')
280	                && (i + 1 >= b.len() || b[i + 1] != ' ')
281	            {
282	                n += 1;
283	            }
284	        }
285	        n
286	    };
287	    // abbreviation-name tokens (2 uppercase letters + digits, e.g. KD19, EX1)
288	    let nabbr = {
289	        let b: Vec<char> = flat.chars().collect();
290	        let mut n = 0i64;
291	        let mut i = 0;
292	        while i < b.len() {
293	            if b[i].is_ascii_uppercase()
294	                && (i == 0 || !(b[i - 1].is_alphanumeric() || b[i - 1] == '_'))
295	            {
296	                let mut j = i + 1;
297	                while j < b.len() && b[j].is_ascii_uppercase() {
298	                    j += 1;
299	                }
300	                let letters = j - i;
301	                let ds = j;
302	                while j < b.len() && b[j].is_ascii_digit() {
303	                    j += 1;
304	                }
305	                if letters <= 2 && j > ds && (j >= b.len() || !(b[j].is_alphanumeric() || b[j] == '_')) {
306	                    n += 1;
307	                }
308	                i = j;
309	            } else {
310	                i += 1;
311	            }
312	        }
313	        n
314	    };
315	    if let Some(open) = flat.find("( ") {
316	        if flat.ends_with(" )") {
317	            let name = &flat[..open];
318	            if !name.is_empty() && !name.contains(['(', ')', '<', '>', ' ', ',']) {
319	                let inner = &flat[open + 2..flat.len() - 2];
320	                let args = split_args(inner);
321	                nargs = args.len() as i64;
322	                for a in &args {
323	                    tuple_nodes(a, true, &mut dtop, &mut drec);
324	                    let t = a.trim();
325	                    let elems = if t.starts_with('<') && t.ends_with('>') {
326	                        split_args(&t[1..t.len() - 1]).len() as i64
327	                    } else {
328	                        union_elems(t)
329	                    };
330	                    if elems >= 2 {
331	                        ctup += elems + 1;
332	                        bmax = bmax.max(elems / 2 + 2);
333	                    }
334	                }
335	                if args.len() == 1 {
336	                    let a = args[0].trim();
337	                    if a.starts_with('\'') && a.ends_with('\'') && a.len() >= 2
338	                        && !a[1..a.len() - 1].contains('\'')
339	                    {
340	                        sqa = 1;
341	                    }
342	                }
343	            }
344	        }
345	    }
346	    (dtop, drec, nq, sqa, nargs, nfunc, nabbr, ctup, bmax)
347	}
