349	fn process_file(path: &std::path::Path, cache: &mut HashMap<(String, String), String>) -> Vec<String> {
350	    let mut out = Vec::new();
351	    let Ok(dot) = std::fs::read_to_string(path) else { return out };
352	    let base = path.file_name().unwrap().to_string_lossy().to_string();
353	    for line in dot.lines() {
354	        if !line.contains("shape=\"record\"") {
355	            continue;
356	        }
357	        let Some(ls) = line.find("label=\"") else { continue };
358	        let after = &line[ls + 7..];
359	        let Some(le) = after.find("\",fillcolor") else { continue };
360	        let Some(groups) = parse_record(&after[..le]) else { continue };
361	        // locate the info group; groups before = P, after = C
362	        let mut info_idx = None;
363	        let mut info_flat = 0usize;
364	        for (gi, cells) in groups.iter().enumerate() {
365	            if cells.len() == 1 {
366	                if let Some(b) = strip_port(&cells[0]) {
367	                    if is_info_body(b) {
368	                        info_idx = Some(gi);
369	                        info_flat = flat_width(b);
370	                    }
371	                }
372	            }
373	        }
374	        let Some(info_idx) = info_idx else { continue };
375	        let group_flats: Vec<Option<Vec<usize>>> = groups
376	            .iter()
377	            .map(|cells| {
378	                cells
379	                    .iter()
380	                    .map(|c| strip_port(c).map(flat_width))
381	                    .collect::<Option<Vec<usize>>>()
382	            })
383	            .collect();
384	        let flats_str = |gi: usize| -> String {
385	            if gi >= groups.len() {
386	                return String::new();
387	            }
388	            match &group_flats[gi] {
389	                Some(v) => v.iter().map(|f| f.to_string()).collect::<Vec<_>>().join(","),
390	                None => String::new(),
391	            }
392	        };
393	        // premise group (if any) is the group before info; conclusion after
394	        let prem_gi = if info_idx > 0 { Some(info_idx - 1) } else { None };
395	        let concl_gi = if info_idx + 1 < groups.len() { Some(info_idx + 1) } else { None };
396	        for (kind, gi) in [("P", prem_gi), ("C", concl_gi)] {
397	            let Some(gi) = gi else { continue };
398	            let cells = &groups[gi];
399	            let bodies: Vec<&str> = match cells.iter().map(|c| strip_port(c)).collect::<Option<Vec<_>>>() {
400	                Some(b) => b,
401	                None => continue,
402	            };
403	            if bodies.iter().any(|b| is_info_body(b)) {
404	                continue;
405	            }
406	            let flats: Vec<usize> = bodies.iter().map(|b| flat_width(b)).collect();
407	            let total: usize = flats.iter().sum();
408	            let any_wrap = bodies.iter().any(|b| b.contains("\\l"));
409	            let dump = if bodies.len() >= 2 {
410	                any_wrap || total > 80
411	            } else {
412	                any_wrap
413	            };
414	            if !dump {
415	                continue;
416	            }
417	            let mut cellfields = Vec::with_capacity(bodies.len());
418	            for (k, body) in bodies.iter().enumerate() {
419	                let flat_text = dewrap(body);
420	                let key = (flat_text.clone(), body.to_string());
421	                let status = if let Some(s) = cache.get(&key) {
422	                    s.clone()
423	                } else {
424	                    let s = cell_status(&flat_text, body, flats[k]);
425	                    cache.insert(key, s.clone());
426	                    s
427	                };
428	                let (dtop, drec, nq, sqa, nargs, nfunc, nabbr, ctup, bmax) = shape_features(&flat_text);
429	                cellfields.push(format!(
430	                    "{}:{}:{}:{}:{}:{}:{}:{}:{}:{}:{}",
431	                    flats[k], status, dtop, drec, nq, sqa, nargs, nfunc, nabbr, ctup, bmax
432	                ));
433	            }
434	            out.push(format!(
435	                "{}\t{}\t{}\t{}\t{}\t{}",
436	                base,
437	                kind,
438	                info_flat,
439	                prem_gi.map(flats_str).unwrap_or_default(),
440	                concl_gi.map(flats_str).unwrap_or_default(),
441	                cellfields.join("|")
442	            ));
443	        }
444	    }
445	    out
446	}
