448	fn main() {
449	    let dirs: Vec<String> = std::env::args().skip(1).collect();
450	    let mut files: Vec<std::path::PathBuf> = Vec::new();
451	    for d in &dirs {
452	        for e in std::fs::read_dir(d).unwrap() {
453	            let p = e.unwrap().path();
454	            if p.extension().and_then(|e| e.to_str()) == Some("dot") {
455	                files.push(p);
