62	/// Split `s` at top-level `", "` separators, honoring `()`/`<>`/`[]` nesting and
63	/// `'…'` quotes. Returns the comma-separated pieces (each un-trimmed).
64	pub fn split_top_commas(s: &str) -> Vec<String> {
65	    let chars: Vec<char> = s.chars().collect();
66	    let mut parts: Vec<String> = Vec::new();
67	    let mut cur = String::new();
68	    let mut depth = 0i32;
69	    let mut in_quote = false;
70	    let mut i = 0;
71	    while i < chars.len() {
72	        let c = chars[i];
73	        if in_quote {
74	            cur.push(c);
75	            if c == '\'' {
76	                in_quote = false;
77	            }
78	            i += 1;
79	            continue;
80	        }
81	        match c {
82	            '\'' => {
83	                in_quote = true;
84	                cur.push(c);
85	                i += 1;
86	            }
87	            '(' | '<' | '[' => {
88	                depth += 1;
89	                cur.push(c);
90	                i += 1;
91	            }
92	            ')' | '>' | ']' => {
93	                depth -= 1;
94	                cur.push(c);
95	                i += 1;
96	            }
97	            ',' if depth == 0 && i + 1 < chars.len() && chars[i + 1] == ' ' => {
98	                parts.push(std::mem::take(&mut cur));
99	                i += 2;
100	            }
101	            _ => {
102	                cur.push(c);
103	                i += 1;
104	            }
105	        }
106	    }
107	    parts.push(cur);
108	    parts
109	}
