184	/// An unpadded function application `name(args)`: identifier directly followed
185	/// by `(` (no space after) with the matching `)` closing the string. Returns
186	/// `(name, args)`.
187	fn func_parts(s: &str) -> Option<(&str, Vec<String>)> {
188	    let open = s.find('(')?;
189	    if open == 0 || !s.ends_with(')') || s.len() < open + 2 {
190	        return None;
191	    }
192	    let name = &s[..open];
193	    if !name.chars().all(|c| c.is_alphanumeric() || c == '_' || c == '!') {
194	        return None;
195	    }
196	    let inner = &s[open + 1..s.len() - 1];
197	    if inner.starts_with(' ') {
198	        return None; // padded fact form, not a function application
199	    }
200	    // the closing paren must match the opening one (reject `f(x)^g(y)`)
201	    let mut depth = 0i32;
202	    let mut in_quote = false;
203	    for (idx, c) in s.char_indices() {
204	        if in_quote {
205	            if c == '\'' {
206	                in_quote = false;
207	            }
208	            continue;
209	        }
210	        match c {
211	            '\'' => in_quote = true,
212	            '(' | '<' | '[' => depth += 1,
213	            ')' | '>' | ']' => {
214	                depth -= 1;
215	                if depth == 0 && idx != s.len() - 1 {
216	                    return None;
217	                }
218	            }
