                              bonus=cbmax, rec=rec, nargs=cnargs, ltup=ltup,
                              rec5=rec5, rec7=rec7, rec9=rec9))
        if ok and cells:
            rows.append((p[0], cells))
    return rows

def hd(x):
    fl = math.floor(x)
    return int(fl) if abs(x - fl - 0.5) < 1e-9 else int(math.floor(x + 0.5))

def run(rows, ckey, nkey):
    ff = fw = fill_hit = fill_tot = 0
    for fname, cells in rows:
        n = len(cells)
        C = [c["f"] + c[ckey] for c in cells]
        S = sum(C)
        N = [c["f"] + c[nkey] + c["nfunc"] for c in cells]
        bon = [c["bonus"] if c["ltup"] else 0 for c in cells]
        pw = []
        for i, c in enumerate(cells):
            b_t = 87 if n == 1 else max(87 + bon[i] - (S - C[i]), 20)
            pw.append(c["f"] > b_t)
        fills = [None] * n
        for i, c in enumerate(cells):
            if not pw[i]:
                continue
            if n == 1:
                fills[i] = 87
                continue
            t = float(N[i])
            for j, cj in enumerate(cells):
                if j != i:
                    w = 5.0/6.0 if (cj["sqa"] and (cells[i]["tup"] + cells[i]["uni"]) > 0) else 1.0
                    t += w * C[j]
            b = hd(87.0 * N[i] / t)
            fills[i] = max(20, min(b, max(c["f"] - 1, 20)))
        final_wrap = list(pw)
        for i, c in enumerate(cells):
            if not pw[i] or n == 1:
                continue
            tot = 0
            for j in range(n):
                if j == i: continue
                if pw[j] and fills[j] < cells[j]["f"] - 2:
                    tot += fills[j]
                else:
                    tot += C[j]
            if c["f"] <= max(87 - tot, 20):
